#include <stdio.h>
#include <string.h>
#include <stdlib.h>

#define N 100000

int main() {
    int T, L, R, K, i, j, ans, cnt, x, y;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d %d", &L, &R, &K);
        ans = 0;
        for (i = L; i <= R; i++) {
            cnt = 0;
            x = i;
            while (x) {
                if (x & 1) cnt++;
                x >>= 1;
            }
            if (cnt >= K) {
                y = i;
                while (y) {
                    if (y & 1) ans |= y;
                    y >>= 1;
                }
            }
        }
        printf("%d\n", ans);
    }
    return 0;
}

