                cnt = 0;
                x = i;
                while (x > 0) {
                    if (x % 2 == 1) cnt++;
                    x >>= 1;
                }
                if (cnt >= K) {
                    y = i;
                    while (y > 0) {
                        if (y % 2 == 1) ans |= y;
                        y >>= 1;
                    }
                }
            }
            System.out.println(ans);
        }
    }
}

